VALUES
  ('real-estate-moex-02962', 'real-estate', 'real-estate-moex-096-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲向乙承租一透天厝，月租3萬元，押租金6萬元，租期為民國96年1月1日至民國98年1月1日， 請問下列何者為真？', '["甲乙間之租賃契約，租期逾1年，卻未以字據訂立，因此無效", "甲於屋內釘掛壁畫及吊飾，不慎造成牆壁破洞，應對乙負賠償責任", "甲因母喪需至美國處理後事，將離開台灣3個月，依法得請求免除未使用租賃期間之租金", "甲住進透天厝 1 個月後才發現，後陽台加蓋部分之鐵皮已破損，隨時可能砸傷自己，因此主張撤銷契 約，並有法律上之依據"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "0c46698332e8", "answer_pdf_sha1": "851f00a4dce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02963', 'real-estate', 'real-estate-moex-096-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '以下何者為真？', '["被繼承人死亡時，繼承人尚生存，始有繼承權，此為同時繼承原則", "繼承人應於知悉其得繼承之時起6個月內通知法院為拋棄繼承之意思表示", "二人如同時死亡，其相互間並無繼承權", "未出生之胎兒無法享有繼承權，也就是繼承人為遺腹子，無法分配遺產"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "0c46698332e8", "answer_pdf_sha1": "851f00a4dce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02964', 'real-estate', 'real-estate-moex-096-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於動產與不動產之區分，下列何者為真？', '["動產與不動產均得為先占之客體", "不動產以登記為權利變動之方式，動產則是交付", "不動產包括土地及其出產物", "不動產可設定抵押權，動產則以典權為主"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "0c46698332e8", "answer_pdf_sha1": "851f00a4dce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02965', 'real-estate', 'real-estate-moex-096-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙結婚膝下無子，甲死亡後乙單獨繼承甲之房屋，請問以下何者為真？', '["乙於辦妥繼承登記後，取得甲之房屋所有權", "乙於甲死亡時，取得甲之房屋所有權", "乙於取得房屋所有權時，即得處分該房屋", "乙須占有該房屋之後，方得處分該屋"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "0c46698332e8", "answer_pdf_sha1": "851f00a4dce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02966', 'real-estate', 'real-estate-moex-096-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙丙三人合買一台價值66萬元之汽車，各自出資22萬元。假設某甲覺得該車音響效果不佳，欲更換 較佳之5萬元音響，請問甲應得何人之同意方得進行更換？', '["應得乙或丙至少一人之同意", "不須得他人同意，自己決定", "乙丙兩人都同意才可", "應取得父母同意"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "0c46698332e8", "answer_pdf_sha1": "851f00a4dce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02967', 'real-estate', 'real-estate-moex-096-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '以所有之意思和平繼續占有他人未登記之不動產，而其占有之時，為善意並無過失者，得請求登記為所有 人之時效為幾年？', '["10年", "5年", "15年", "20年"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "0c46698332e8", "answer_pdf_sha1": "851f00a4dce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02968', 'real-estate', 'real-estate-moex-096-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙婚後育有三子ABC，共同經營一家工廠，一日甲與A前去香港洽談生意，回程時飛機漏油爆炸，甲 與A同時遇難，無法證明何人先死。甲遺下2000萬元遺產，A遺下300萬元遺產，請問以下敘述何者為 真？', '["甲死亡後，乙得繼承甲之遺產500萬元", "設A死亡後遺有一妻一女，則乙得繼承A之遺產100萬元", "設A死亡時未娶妻生子，則B、C各得繼承100萬元", "設A死亡後遺有一妻一女，則B、C無繼承權"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "0c46698332e8", "answer_pdf_sha1": "851f00a4dce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02969', 'real-estate', 'real-estate-moex-096-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何者非代理權之限制？', '["表見代理", "雙方代理", "自己代理", "共同代理"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "0c46698332e8", "answer_pdf_sha1": "851f00a4dce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02970', 'real-estate', 'real-estate-moex-096-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何者之情形，贈與人得撤銷其贈與？', '["經公證之贈與", "履行道德上義務之贈與", "立有字據之贈與", "贈與物之權利已移轉"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "0c46698332e8", "answer_pdf_sha1": "851f00a4dce5", "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
